func Xerror_message(cgtls *iqlibc.ppTLS, aacode tnerrcode_t) (cgr ppuintptr) {

	var aacp, aaet, aamsg, aamsg1, ccv4, ccv5, ccv6 ppuintptr
	var aaoffset, aastarted ppint32
	var aatable_num tnerrcode_t
	pp_, pp_, pp_, pp_, pp_, pp_, pp_, pp_, pp_, pp_ = aacp, aaet, aamsg, aamsg1, aaoffset, aastarted, aatable_num, ccv4, ccv5, ccv6
	aastarted = 0

	aaoffset = ppint32(aacode & ppint64(iqlibc.ppInt32FromInt32(1)<<iqlibc.ppInt32FromInt32(mvERRCODE_RANGE)-iqlibc.ppInt32FromInt32(1)))
	aatable_num = aacode - ppint64(aaoffset)
	if aatable_num == mvSYS_ERR_BASE {
		aacp = Xstrerror(cgtls, ppint32(aacode))
		if aacp != 0 {
			return aacp
		} else {
			goto ppoops
		}
	}
	Xet_list_lock(cgtls)
	aaet = X_et_list
	for {
		if !(aaet != 0) {
			break
		}
		if (*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdbase&ppint64(0xffffff) == aatable_num&ppint64(0xffffff) {
			/* This is the right table */
			if (*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdn_msgs <= aaoffset {
				break
			} else {
				aamsg = *(*ppuintptr)(iqunsafe.ppPointer((*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdmsgs + ppuintptr(aaoffset)*8))
				Xet_list_unlock(cgtls)
				if sicom_err_gettext != 0 {
					return (*(*func(*iqlibc.ppTLS, ppuintptr) ppuintptr)(iqunsafe.ppPointer(&struct{ ppuintptr }{sicom_err_gettext})))(cgtls, aamsg)
				} else {
					return aamsg
				}
			}
		}

		goto cg_1
	cg_1:
		;
		aaet = (*tset_list)(iqunsafe.ppPointer(aaet)).fdnext
	}
	aaet = X_et_dynamic_list
	for {
		if !(aaet != 0) {
			break
		}
		if (*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdbase&ppint64(0xffffff) == aatable_num&ppint64(0xffffff) {
			/* This is the right table */
			if (*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdn_msgs <= aaoffset {
				break
			} else {
				aamsg1 = *(*ppuintptr)(iqunsafe.ppPointer((*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aaet)).fdtable)).fdmsgs + ppuintptr(aaoffset)*8))
				Xet_list_unlock(cgtls)
				if sicom_err_gettext != 0 {
					return (*(*func(*iqlibc.ppTLS, ppuintptr) ppuintptr)(iqunsafe.ppPointer(&struct{ ppuintptr }{sicom_err_gettext})))(cgtls, aamsg1)
				} else {
					return aamsg1
				}
			}
		}

		goto cg_2
	cg_2:
		;
		aaet = (*tset_list)(iqunsafe.ppPointer(aaet)).fdnext
	}
	Xet_list_unlock(cgtls)
	goto ppoops
ppoops:
	;
	Xstrcpy(cgtls, ppuintptr(iqunsafe.ppPointer(&sibuffer)), "Unknown code \x00")
	if aatable_num != 0 {
		Xstrcat(cgtls, ppuintptr(iqunsafe.ppPointer(&sibuffer)), Xerror_table_name(cgtls, aatable_num))
		Xstrcat(cgtls, ppuintptr(iqunsafe.ppPointer(&sibuffer)), " \x00")
	}
	aacp = ppuintptr(iqunsafe.ppPointer(&sibuffer))
	for {
		if !(*(*ppint8)(iqunsafe.ppPointer(aacp)) != 0) {
			break
		}

		goto cg_3
	cg_3:
		;
		aacp = aacp + 1
	}
	if aaoffset >= ppint32(100) {
		ccv4 = aacp
		aacp = aacp + 1
		*(*ppint8)(iqunsafe.ppPointer(ccv4)) = ppint8(ppint32('0') + aaoffset/ppint32(100))
		aaoffset = aaoffset % ppint32(100)
		aastarted = aastarted + 1
	}
	if aastarted != 0 || aaoffset >= ppint32(10) {
		ccv4 = aacp
		aacp = aacp + 1
		*(*ppint8)(iqunsafe.ppPointer(ccv4)) = ppint8(ppint32('0') + aaoffset/ppint32(10))
		aaoffset = aaoffset % ppint32(10)
	}
	ccv4 = aacp
	aacp = aacp + 1
	*(*ppint8)(iqunsafe.ppPointer(ccv4)) = ppint8(ppint32('0') + aaoffset)
	*(*ppint8)(iqunsafe.ppPointer(aacp)) = ppint8('\000')
	return ppuintptr(iqunsafe.ppPointer(&sibuffer))
}

// C documentation
//
//	/*
//	 * This routine will only return a value if the we are not running as
//	 * a privileged process.
//	 */
func sisafe_getenv(cgtls *iqlibc.ppTLS, aaarg ppuintptr) (cgr ppuintptr) {

	/* go2fs: getgid/getegid removed - not implemented in modernc/libc
	   on darwin/arm64. Only used for setuid detection, irrelevant for
	   image-file filesystem creation. */
	/* if ((getuid() != geteuid()) || (getgid() != getegid())) */
	if Xgetuid(cgtls) != Xgeteuid(cgtls) {
		return iqlibc.ppUintptrFromInt32(0)
	}

	return Xgetenv(cgtls, aaarg)
}

var sidebug_mask = ppint32(0)
var sidebug_f = ppuintptr(0)

func siinit_debug(cgtls *iqlibc.ppTLS) {
	cgbp := cgtls.ppAlloc(32)
	defer cgtls.ppFree(32)

	var aadstr, aafn ppuintptr
	var aafd, aaflags ppint32
	var pp_ /* tmp at bp+0 */ ppuintptr
	pp_, pp_, pp_, pp_ = aadstr, aafd, aaflags, aafn

	if sidebug_mask&ppint32(mvDEBUG_INIT) != 0 {
		return
	}

	aadstr = Xgetenv(cgtls, "COMERR_DEBUG\x00")
	if aadstr != 0 {
		sidebug_mask = iqlibc.ppInt32FromUint64(Xstrtoul(cgtls, aadstr, cgbp, 0))
		if *(*ppint8)(iqunsafe.ppPointer(*(*ppuintptr)(iqunsafe.ppPointer(cgbp)))) != 0 || *(*ppint32)(iqunsafe.ppPointer(X__error(cgtls))) != 0 {
			sidebug_mask = 0
		}
	}

	sidebug_mask = sidebug_mask | ppint32(mvDEBUG_INIT)
	if sidebug_mask == ppint32(mvDEBUG_INIT) {
		return
	}

	aafn = sisafe_getenv(cgtls, "COMERR_DEBUG_FILE\x00")
	if aafn != 0 {
		sidebug_f = Xfopen(cgtls, aafn, "a\x00")
	}
	if !(sidebug_f != 0) {
		sidebug_f = Xfopen(cgtls, "/dev/tty\x00", "a\x00")
	}
	if sidebug_f != 0 {
		aafd = Xfileno(cgtls, sidebug_f)

		if aafd >= 0 {
			aaflags = Xfcntl(cgtls, aafd, ppint32(mvF_GETFD), 0)

			if aaflags >= 0 {
				aaflags = Xfcntl(cgtls, aafd, ppint32(mvF_SETFD), iqlibc.ppVaList(cgbp+16, aaflags|ppint32(mvFD_CLOEXEC)))
			}
			if aaflags < 0 {
				Xfprintf(cgtls, sidebug_f, "Couldn't set FD_CLOEXEC on debug FILE: %s\n\x00", iqlibc.ppVaList(cgbp+16, Xstrerror(cgtls, *(*ppint32)(iqunsafe.ppPointer(X__error(cgtls))))))
				Xfclose(cgtls, sidebug_f)
				sidebug_f = iqlibc.ppUintptrFromInt32(0)
				sidebug_mask = ppint32(mvDEBUG_INIT)
			}
		}
	} else {
		sidebug_mask = ppint32(mvDEBUG_INIT)
	}
}

// C documentation
//
//	/*
//	 * New interface provided by krb5's com_err library
//	 */
func Xadd_error_table(cgtls *iqlibc.ppTLS, aaet ppuintptr) (cgr tnerrcode_t) {
	cgbp := cgtls.ppAlloc(32)
	defer cgtls.ppFree(32)

	var aael, ccv1 ppuintptr
	pp_, pp_ = aael, ccv1

	ccv1 = Xmalloc(cgtls, ppuint64(16))
	aael = ccv1
	if !(ccv1 != 0) {
		return ppint64(mvENOMEM)
	}

	if Xet_list_lock(cgtls) != 0 {
		Xfree(cgtls, aael)
		return ppint64(*(*ppint32)(iqunsafe.ppPointer(X__error(cgtls))))
	}

	(*tset_list)(iqunsafe.ppPointer(aael)).fdtable = aaet
	(*tset_list)(iqunsafe.ppPointer(aael)).fdnext = X_et_dynamic_list
	X_et_dynamic_list = aael

	siinit_debug(cgtls)
	if sidebug_mask&ppint32(mvDEBUG_ADDREMOVE) != 0 {
		Xfprintf(cgtls, sidebug_f, "add_error_table: %s (0x%p)\n\x00", iqlibc.ppVaList(cgbp+8, Xerror_table_name(cgtls, (*tserror_table)(iqunsafe.ppPointer(aaet)).fdbase), aaet))
	}

	Xet_list_unlock(cgtls)
	return 0
}

// C documentation
//
//	/*
//	 * New interface provided by krb5's com_err library
//	 */
func Xremove_error_table(cgtls *iqlibc.ppTLS, aaet ppuintptr) (cgr tnerrcode_t) {
	cgbp := cgtls.ppAlloc(32)
	defer cgtls.ppFree(32)

	var aael, aael2 ppuintptr
	pp_, pp_ = aael, aael2
	aael2 = ppuintptr(0)

	if Xet_list_lock(cgtls) != 0 {
		return ppint64(mvENOENT)
	}

	aael = X_et_dynamic_list
	siinit_debug(cgtls)
	for aael != 0 {
		if (*tserror_table)(iqunsafe.ppPointer((*tset_list)(iqunsafe.ppPointer(aael)).fdtable)).fdbase == (*tserror_table)(iqunsafe.ppPointer(aaet)).fdbase {
			if aael2 != 0 { /* Not the beginning of the list */
				(*tset_list)(iqunsafe.ppPointer(aael2)).fdnext = (*tset_list)(iqunsafe.ppPointer(aael)).fdnext
			} else {
				X_et_dynamic_list = (*tset_list)(iqunsafe.ppPointer(aael)).fdnext
			}
			Xfree(cgtls, aael)
			if sidebug_mask&ppint32(mvDEBUG_ADDREMOVE) != 0 {
				Xfprintf(cgtls, sidebug_f, "remove_error_table: %s (0x%p)\n\x00", iqlibc.ppVaList(cgbp+8, Xerror_table_name(cgtls, (*tserror_table)(iqunsafe.ppPointer(aaet)).fdbase), aaet))
			}
			Xet_list_unlock(cgtls)
			return 0
		}
		aael2 = aael
		aael = (*tset_list)(iqunsafe.ppPointer(aael)).fdnext
	}
	if sidebug_mask&ppint32(mvDEBUG_ADDREMOVE) != 0 {
		Xfprintf(cgtls, sidebug_f, "remove_error_table FAILED: %s (0x%p)\n\x00", iqlibc.ppVaList(cgbp+8, Xerror_table_name(cgtls, (*tserror_table)(iqunsafe.ppPointer(aaet)).fdbase), aaet))
	}
	Xet_list_unlock(cgtls)
	return ppint64(mvENOENT)
}

// C documentation
//
//	/*
//	 * Variant of the interface provided by Heimdal's com_err library
//	 */
func Xadd_to_error_table(cgtls *iqlibc.ppTLS, aanew_table ppuintptr) {

	Xadd_error_table(cgtls, (*tset_list)(iqunsafe.ppPointer(aanew_table)).fdtable)
}

